fixed_code:
fn main() {
    use std::collections::HashMap;

    fn intern(pool: &mut HashMap<String, usize>, s: String) -> usize {
        if let Some(&id) = pool.get(s.as_str()) {
            id
        } else {
            let id = pool.len();
            pool.insert(s.clone(), id);
            id
        }
    }

    let mut pool = HashMap::new();

    let s1 = intern(&mut pool, String::from("hello"));
    let s2 = intern(&mut pool, String::from("hello"));
    println!("{} == {}", s1, s2);
}
